input.commands:
awk '
function trim(s){ sub(/^[ \t\r]+/,"",s); sub(/[ \t\r]+$/,"",s); return s }
function add_section(s){ if(!(s in sec_seen)){ sec_seen[s]=1; sec_list[++sec_count]=s } }
function add_key(s,k){ sk=s SUBSEP k; if(!(sk in key_seen)){ key_seen[sk]=1; key_list[s]=key_list[s] k "\034" } }
{
  line=$0
  if(line ~ /^[ \t]*$/) next
  if(line ~ /^[ \t]*[;#]/) next

  if(match(line,/^[ \t]*\[[^][]+\][ \t]*$/)){
    sec=line
    sub(/^[ \t]*\[/,"",sec)
    sub(/\][ \t]*$/,"",sec)
    sec=trim(sec)
    add_section(sec)
    current=sec
    next
  }

  eq=index(line,"=")
  if(eq>0 && current!=""){
    k=trim(substr(line,1,eq-1))
    v=substr(line,eq+1)
    add_key(current,k)
    val[current SUBSEP k]=v
  }
}
END{
  for(i=1;i<=sec_count;i++){
    s=sec_list[i]
    if(i>1) print ""
    print "[" s "]"
    n=split(key_list[s],arr,"\034")
    for(j=1;j<=n;j++){
      k=arr[j]
      if(k=="") continue
      print k "=" val[s SUBSEP k]
    }
  }
}
' /config/defaults.ini /config/custom.ini > /config/merged.ini

